'use strict';

const https=require('https');
const http=require('http');

function naver(q,tl){
  // q: query string
  // tl: target language
  return new Promise(function (resolve,reject){
    if(typeof q!=='string' || q.trim().length===0){
      resolve([]);
    }
    q=encodeURIComponent(q);

    if(typeof tl!=='string') tl='cn';
    tl=tl.toLowerCase();

    let req, _p,
    _y=function(res){
      let s=[],i=0;
      
      // console.debug(res.statusCode);
      if(res.statusCode!==200) resolve([]);

      res.on('data',d=>{
        i+=d.length;
        s.push(d);
      });
      res.on('end',()=>{
        let r=Buffer.concat(s,i).toString('utf8');
        r=_p(r);
        // console.debug(r)
        resolve(r);
      });
    },
    _n=function(v){y([])},
    _p1=function(s){
      let j=JSON.parse(s);
      let r=[];

      // console.debug(j.items.map(e=>e.map(e=>e.map(e=>e[0]))));

      j.items.forEach(e=>{
        e.forEach(e=>{
          let a=e.map(e=>e[0]);
          r.push([a[5],a[1],a[2]]);
        })
      });
      return r;
    },
    _p2=function(s){
      // console.debug(s);// 
      let j=JSON.parse(s);
      let r=[];
      // console.debug(j.items.map(e=>e.map(e=>e[0])));
      j.items.forEach(e=>{
        let a=e.map(e=>e[0]);
        r=r.concat(a);
        // console.log(a)
      });
      return r;
    },
    _p3=function(s){
      // console.debug(s);
      let j=JSON.parse(s);
      let r=j.items.map(e=>{
        let a=e.split('|');
        return a.slice(1)
      });
      return r;
    },
    _p4=function(s){
      // console.debug(s);// items:[ [[s],[t]] ]
      let j=JSON.parse(s);
      let r=[];
      j.items.map(e=>e.map(e=>{
        let a=e.map(e=>e[0]);
        // console.debug('---', a)
        r.push({s:a[0],t:a[1]});
      }));
      return r;
    },
    _p5=function(s){
      console.debug(s.toString());
    };

    if(tl==='cn') _p=_p1, req=https.get('https://ac.dict.naver.com/zhdict/ac?mod=json&st=11&r_lt=10&q='+q, _y).on('error',_n);
    if(tl==='k')  _p=_p2, req=https.get('https://ac.dict.naver.com/krdic/ac?frm=stdkrdic&oe=utf8&m=0&r=1&st=111&r_lt=111&q='+q, _y).on('error',_n);
    if(tl==='ch') _p=_p3, req=http.get('http://suggest-bar.daum.net/suggest?mod=json&code=utf_in_out&enc=utf&id=language&cate=han&q='+q, _y).on('error',_n);
    if(tl==='jp') _p=_p4, req=https.get('https://ja.dict.naver.com/ac?st=111&r_lt=111&n_kojpdic=1&q='+q, _y).on('error',_n);
  });
};


